mapper.update:
UPDATE PAYMENT
SET PAY_STTS_CD = 'CANCEL',
    FAIL_RSN_CN = #{failRsnCn}
WHERE PYMT_NO = #{pymtNo}
  AND ORD_ID = #{ordId}
  AND PAY_STTS_CD = 'UNPAID'

UPDATE BILL
SET PYMT_STTS_CD = 'PAID',
    PYMT_DT = SYSDATE,
    PYMT_AMT = #{payAmt}
WHERE BILL_NO = #{billNo}
  AND PYMT_STTS_CD != 'PAID'
